  ('bookkeeper-moex-00866', 'bookkeeper', 'bookkeeper-moex-107-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依現行所得稅法規定，下列何項個人所得應併入綜合所得總額課徵綜合所得稅？', '["出售於100年中繼承取得土地之交易所得", "未超過18萬之稿費收入", "百貨公司周年慶之中奬奬金", "大學入學考試命題酬勞"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:25+00:00", "source_pdf_sha1": "4a020fb6864b", "answer_pdf_sha1": "188805b3360a", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
